import ast
import operator


def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        # Parse the expression into an AST
        tree = ast.parse(expr.strip(), mode='eval')

        # Define allowed operations mapping
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Pow: operator.pow,
            ast.Mod: operator.mod,
            ast.FloorDiv: operator.floordiv,
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
        }

        def evaluate(node):
            if isinstance(node, ast.Expression):
                return evaluate(node.body)
            elif isinstance(node, ast.Constant):
                # Only allow numeric constants
                if isinstance(node.value, (int, float)):
                    return node.value
                raise ValueError("Only numeric constants are allowed")
            elif isinstance(node, ast.Num):  # Python 3.7 compatibility
                return node.n
            elif isinstance(node, ast.BinOp):
                left = evaluate(node.left)
                right = evaluate(node.right)
                op_func = ops.get(type(node.op))
                if op_func is None:
                    raise ValueError(f"Unsupported binary operation: {type(node.op).__name__}")
                return op_func(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = evaluate(node.operand)
                op_func = ops.get(type(node.op))
                if op_func is None:
                    raise ValueError(f"Unsupported unary operation: {type(node.op).__name__}")
                return op_func(operand)
            else:
                raise ValueError(f"Unsupported node type: {type(node).__name__}")

        result = evaluate(tree)

        # Format result - use int format if it's a whole number
        if isinstance(result, float):
            if result.is_integer():
                return str(int(result))
            return str(result)
        return str(result)

    except (ValueError, SyntaxError, TypeError, ZeroDivisionError, OverflowError):
        return ""

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=["HS256"])
    except jwt.InvalidTokenError:
        return {}

