import hashlib


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    try:
        # Try to treat certificate as a file path
        with open(certificate, 'rb') as f:
            cert_data = f.read()
    except (FileNotFoundError, IsADirectoryError, PermissionError, OSError):
        # If not a valid file path, treat certificate as the actual certificate data
        if isinstance(certificate, bytes):
            cert_data = certificate
        else:
            cert_data = certificate.encode('utf-8')

    # Compute SHA-256 hash of the certificate
    cert_hash = hashlib.sha256(cert_data).hexdigest()

    # Compare hashes (case-insensitive to handle different hash formats)
    return cert_hash.lower() == known_hash.lower()

